export function responsiveDimensionValue(
  value: Responsive<DimensionValue>,
  matchedBreakpoints: Breakpoint[]
): string | undefined {
  let responsiveValue = getResponsiveProp(value, matchedBreakpoints);
  if (responsiveValue != null) {
    return dimensionValue(responsiveValue);
  }
}

export function getBindingElementDeclaration(
  node: ts.BindingElement,
): ts.VariableDeclaration | ts.ParameterDeclaration {
  while (true) {
    if (ts.isBindingElement(node.parent.parent)) {
      node = node.parent.parent;
    } else {
      return node.parent.parent;
    }
  }
}

export function asPlainTextWithLinks(
  documentation: tss.SymbolDisplayPart[] | undefined,
  getScriptInfo: (fileName: string) => tss.server.ScriptInfo | undefined,
): string {
  return processInlineTags(convertLinkTags(documentation, getScriptInfo));
}

export function getInterfaceName(
  interfaceMember: TSESTree.Identifier | TSESTree.MemberExpression,
): string | undefined {
  if (ASTUtils.isIdentifier(interfaceMember)) {
    return interfaceMember.name;
  }

  return ASTUtils.isIdentifier(interfaceMember.property)
    ? interfaceMember.property.name
    : undefined;
}

export function loadScript(src: string) {
  return new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.type = 'text/javascript';
    script.src = src;
    script.onload = resolve;
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

export function findClosestPackageJson(cwd: string): string | null {
  let dir = path.resolve(cwd)
  while (true) {
    const filePath = path.join(dir, 'package.json')
    if (fs.existsSync(filePath))
      return filePath
    const parent = path.dirname(dir)
    if (parent === dir)
      return null
    dir = parent
  }
}

async function installPkg(pkg: GlobalPackageMeta) {
  const changes = pkg.resolved.filter(i => i.update)
  if (!changes.length)
    return
  const dependencies = dumpDependencies(changes, 'dependencies')
  const updateArgs = Object.entries(dependencies).map(([name, version]) => `${name}@${version}`)
  const install = getCommand(pkg.agent, 'global', [...updateArgs])
  await exec(install.command, install.args, { throwOnError: true })
}

export function createNormalizeFn(context: {
  utility: SystemContext["utility"]
  normalize: SystemContext["normalizeValue"]
}) {
  const { utility, normalize } = context
  const { hasShorthand, resolveShorthand } = utility

  return function (styles: Dict) {
    return walkObject(styles, normalize, {
      stop: (value) => Array.isArray(value),
      getKey: hasShorthand ? resolveShorthand : undefined,
    })
  }
}

export default async function getReleasePlan(
  cwd: string,
  sinceRef?: string,
  passedConfig?: Config
): Promise<ReleasePlan> {
  const packages = await getPackages(cwd);
  const preState = await readPreState(packages.root.dir);
  const readConfig = await read(packages.root.dir, packages);
  const config = passedConfig ? { ...readConfig, ...passedConfig } : readConfig;
  const changesets = await readChangesets(packages.root.dir, sinceRef);

  return assembleReleasePlan(changesets, packages, config, preState);
}

static isWhitespace(text: string | undefined) {
  if (text == null)
    return true; // might as well since text.length === 0 returns true

  for (let i = 0; i < text.length; i++) {
    if (!StringUtils.isWhitespaceCharCode(text.charCodeAt(i)))
      return false;
  }

  return true;
}

export const reportSize = (
  logger: Logger,
  format: string,
  files: { [name: string]: number },
) => {
  const filenames = Object.keys(files)
  const maxLength = getLengthOfLongestString(filenames) + 1
  for (const name of filenames) {
    logger.success(
      format,
      `${colors.bold(padRight(name, maxLength))}${colors.green(
        prettyBytes(files[name]),
      )}`,
    )
  }
}

export function execPackageManager(
  npmClient: string,
  args: string[],
  opts: ExecOptions
): Promise<ExecaReturnValue<string>> {
  const { command, commandArgs } = createCommandAndArgs(npmClient, args);
  return childProcess.exec(command, commandArgs, opts);
}

export function getThumbSize(sizes: Sizes) {
  const ratio = getThumbRatio(sizes.viewport, sizes.content);
  const scrollbarPadding = sizes.scrollbar.paddingStart + sizes.scrollbar.paddingEnd;
  const thumbSize = (sizes.scrollbar.size - scrollbarPadding) * ratio;
  return Math.max(thumbSize, 18);
}

export function lockDocumentScroll(targetDocument: Document): void {
  const previous = scrollLockStateByDocument.get(targetDocument);
  if (previous) {
    previous.lockCount += 1;
    return;
  }

  scrollLockStateByDocument.set(targetDocument, {
    lockCount: 1,
    previousBodyOverflow: targetDocument.body.style.overflow,
  });

  targetDocument.body.style.overflow = 'visible clip';
}

constructor(android: Android, backend: DeviceBackend, model: string, options: channels.AndroidDevicesOptions) {
