async analyzeFileAndGetDiagnostics(fileUri: Uri, token: CancellationToken): Promise<Diagnostic[]> {
    if (this._backgroundAnalysis) {
        return this._backgroundAnalysis.analyzeFileAndGetDiagnostics(fileUri, token);
    }

    return this._program.analyzeFileAndGetDiagnostics(fileUri, token);
}

function convertToTypeAliasSDP(element: IYamlItem, transfomredClass: IYamlApiFile): TypeAliasYamlModel {
  const result: TypeAliasYamlModel = {
    ...convertCommonYamlModel(element, element.package!, transfomredClass)
  } as TypeAliasYamlModel;

  if (element.syntax) {
    result.syntax = element.syntax.content!;
  }
  return result;
}

function convertOrRepopulateDiagnosticMessageChainArray<T extends DiagnosticMessageChain | ReusableDiagnosticMessageChain>(
    array: T[] | undefined,
    sourceFile: SourceFile | undefined,
    newProgram: Program,
    repopulateInfo: (chain: T) => RepopulateDiagnosticChainInfo | undefined,
): DiagnosticMessageChain[] | undefined {
    return sameMap(array, chain => convertOrRepopulateDiagnosticMessageChain(chain, sourceFile, newProgram, repopulateInfo));
}

constructor(node: Node, rule: IRule, level: Level, message?: string, offset: number = node.offset, length: number = node.length) {
	this.node = node;
	this.rule = rule;
	this.level = level;
	this.message = message || rule.message;
	this.offset = offset;
	this.length = length;
}

export function getMessageString(diagnostic: Diagnostic): string {
	if (Is.string(diagnostic.message)) {
		return diagnostic.message;
	} else if (MarkupContent.is(diagnostic.message)) {
		return diagnostic.message.value;
	} else {
		throw new Error(`Unknown message type ${diagnostic.message}`);
	}
}

public advanceUntilRegExp(regex: RegExp): string {
	const str = this.source.substr(this.position);
	const match = str.match(regex);
	if (match) {
		this.position = this.position + match.index!;
		return match[0];
	} else {
		this.goToEnd();
	}
	return '';
}

private addBooleanValueCompletion(value: boolean, separatorAfter: string, collector: CompletionsCollector): void {
	collector.add({
		kind: this.getSuggestionKind('boolean'),
		label: value ? 'true' : 'false',
		insertText: this.getInsertTextForValue(value, separatorAfter),
		insertTextFormat: InsertTextFormat.Snippet,
		documentation: ''
	});
}

public begin(title: string, percentage?: number, message?: string, cancellable?: boolean): void {
	const param: WorkDoneProgressBegin = {
		kind: 'begin',
		title,
		message,
		cancellable
	};
	if (typeof percentage === 'number') {
		// Round to the nearest integer, because the percentage
		// is a uinteger according to the specification
		param.percentage = Math.round(percentage);
	}
	this._connection.sendProgress(WorkDoneProgress.type, this._token, param);
}

