function createProjectRootMappings(
  nodes: Record<string, ProjectGraphProjectNode>
): Map<string, string> {
  const projectRootMappings = new Map<string, string>();
  for (const projectName of Object.keys(nodes)) {
    const root = nodes[projectName].data.root;

    projectRootMappings.set(normalizeProjectRoot(root), projectName);
  }
  return projectRootMappings;
}

function set(newLogger: Logger): void {
  if (cachedLoggers.has(newLogger.namespace)) return
  if (cachedLoggers.has('root')) return

  if (ensureItMatchesInterface(newLogger)) {
    cachedLoggers.set(newLogger.namespace, newLogger)
    cachedLoggers.set('root', newLogger)
  } else {
    process.emitWarning('Logger does not match the Logger interface. Using default logger.')
  }
}

export function getDependencyTypeFromManifest (
  manifest: Pick<ProjectManifest, DependenciesOrPeersField>,
  depName: string
): DependenciesOrPeersField | null {
  if (manifest.optionalDependencies?.[depName]) return 'optionalDependencies'
  if (manifest.dependencies?.[depName]) return 'dependencies'
  if (manifest.devDependencies?.[depName]) return 'devDependencies'
  if (manifest.peerDependencies?.[depName]) return 'peerDependencies'
  return null
}

const formatEsbuildError = (
	error: TransformFailure,
) => {
	error.name = 'TransformError';
	// @ts-expect-error deleting non-option property
	delete error.errors;
	// @ts-expect-error deleting non-option property
	delete error.warnings;
	throw error;
};

export function getPosition(pos: number, lineStartPositions: number[]): Position {
  let line = binarySearch(lineStartPositions, pos);

  if (line < 0) {
    const insertionPoint = -1 * line - 1;
    line = insertionPoint - 1;
  }

  return Position.create(line, pos - lineStartPositions[line]);
}

export function getNextPageParam(
  options: InfiniteQueryConfigOptions<unknown, unknown, unknown>,
  { pages, pageParams }: InfiniteData<unknown, unknown>,
  queryArg: unknown,
): unknown | undefined {
  const lastIndex = pages.length - 1
  return options.getNextPageParam(
    pages[lastIndex],
    pages,
    pageParams[lastIndex],
    pageParams,
    queryArg,
  )
}
